import java.sql.*;
public class Bank {
    private static final String DB_URL = "jdbc:mysql://localhost/bank";
    private static final String USERNAME = "root";
    private static final String PASSWORD = "";

    public static void main(String[] args) throws SQLException, InterruptedException{
        Connection connection = DriverManager.getConnection(DB_URL,USERNAME,PASSWORD);

        Statement statement = connection.createStatement();
        statement.execute("CREATE TABLE IF NOT EXISTS account (account_id int PRIMARY KEY AUTO_INCREMENT, balance double)");
        statement.executeUpdate("INSERT INTO account VALUES(1000,'500')");
        statement.close();

        Thread t1 = new Thread(() -> {
            try{
                Connection connection2 = DriverManager.getConnection(DB_URL,USERNAME,PASSWORD);

                Statement statement2 = connection2.createStatement();
                statement2.execute("CREATE TABLE IF NOT EXISTS transaction (transaction_id int PRIMARY KEY AUTO_INCREMENT, account_id int, amount double)");
                statement2.executeUpdate("INSERT INTO transaction VALUES(100,'1000','5')");
                statement2.close();

                Thread t3 = new Thread(() -> {
                    try{
                        Connection connection3 = DriverManager.getConnection(DB_URL,USERNAME,PASSWORD);

                        Statement statement3 = connection3.createStatement();
                        statement3.execute("CREATE TABLE IF NOT EXISTS account (account_id int PRIMARY KEY AUTO_INCREMENT, balance double)");
                        statement3.executeUpdate("INSERT INTO account VALUES(1000,'500')");
                        statement3.close();
                    }catch (SQLException e){
                        System.out.println(e);
                    }
                });

                t3.start();
            } catch (SQLException e) {
                System.out.println(e);
            }
        });

        Thread t2 = new Thread(() -> {
            try{
                Connection connection4 = DriverManager.getConnection(DB_URL,USERNAME,PASSWORD);

                Statement statement4 = connection4.createStatement();
                statement4.execute("CREATE TABLE IF NOT EXISTS transaction (transaction_id int PRIMARY KEY AUTO_INCREMENT, account_id int, amount double)");
                statement4.executeUpdate("INSERT INTO transaction VALUES(100,'1000','5')");
                statement4.close();
            } catch (SQLException e) {
                System.out.println(e);
            }
        });

        t1.start();
        t2.start();
    }
}

